import java.util.*;final class FuturePromisePattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String code){super(code);this.code=code;}String code(){return code;}}
    @SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){String state="pending",value="none",error="none";List<String>observations=new ArrayList<>();int terminal=0;for(Map<String,Object>action:(List<Map<String,Object>>)input.getOrDefault("actions",List.of())){String op=String.valueOf(action.get("op"));switch(op){case"complete","fail","cancel"->{if(!state.equals("pending"))throw new PatternException("already_completed");terminal++;if(op.equals("complete")){state="fulfilled";value=String.valueOf(action.get("value"));}else if(op.equals("fail")){state="rejected";error=String.valueOf(action.get("code"));}else state="cancelled";}case"observe"->observations.add(state.equals("pending")?"pending":state.equals("fulfilled")?"value:"+value:state.equals("rejected")?"error:"+error:"cancelled");default->throw new PatternException("unknown_action");}}return Map.of("state",state,"observations",observations,"value",value,"error",error,"terminal_count",terminal);}}
